from typing import List

class Solution:
    def MaxPlayers(self, playerCount: int, playerTimeRange: List[List[int]]) -> int:
        # 按照结束时间从小到大排序
        playerTimeRange.sort(key=lambda x: x[1])

        ans = 0
        lastEnd = -1  # 记录上一次安排的结束时间

        # 遍历每个试玩时间区间
        for start, end in playerTimeRange:
            # 允许连续，所以 start 等于 lastEnd 时也可以安排
            if start >= lastEnd:
                ans += 1
                lastEnd = end  # 更新最后安排结束时间

        return ans
```

```java
import java.util.*;

public class Solution {
    public int MaxPlayers(int playerCount, int[][] playerTimeRange) {
        // 按照结束时间从小到大排序
        Arrays.sort(playerTimeRange, new Comparator<int[]>() {
            public int compare(int[] a, int[] b) {
                return Integer.compare(a[1], b[1]);
            }
        });

        int ans = 0;
        int lastEnd = -1; // 记录上次结束时间

        // 依次尝试安排每一个试玩
        for (int i = 0; i < playerCount; i++) {
            int start = playerTimeRange[i][0];
            int end = playerTimeRange[i][1];

            // 若当前试玩开始时间不早于上次结束时间，则可以安排
            if (start >= lastEnd) {
                ans++;
                lastEnd = end;
            }
        }

        return ans;
    }
}
