#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int MaxPlayers(int playerCount, vector<vector<int> >& playerTimeRange) {
        // 按结束时间排序
        sort(playerTimeRange.begin(), playerTimeRange.end(),
             [](const vector<int>& a, const vector<int>& b) {
                 return a[1] < b[1];
             });

        int ans = 0;
        int lastEnd = -1; // 上一个安排的结束时间

        for (int i = 0; i < playerCount; i++) {
            int start = playerTimeRange[i][0];
            int end = playerTimeRange[i][1];

            // 若不冲突则安排当前试玩
            if (start >= lastEnd) {
                ans++;
                lastEnd = end;
            }
        }

        return ans;
    }
};
```

```javascript
/**
 * @param {number} playerCount 试玩申请数量
 * @param {number[][]} playerTimeRange 每个试玩的开始和结束时间数组
 * @return {number} 最多可安排的试玩数量
 */
var MaxPlayers = function(playerCount, playerTimeRange) {
    if (playerTimeRange.length === 0) return 0;

    // 按结束时间从小到大排序
    playerTimeRange.sort((a, b) => a[1] - b[1]);

    let count = 1; // 至少安排一个
    let lastEnd = playerTimeRange[0][1]; // 记录上一次安排结束时间

    // 遍历剩余区间
    for (let i = 1; i < playerTimeRange.length; i++) {
        // 若当前试玩开始时间不早于上次结束时间，则可以安排
        if (playerTimeRange[i][0] >= lastEnd) {
            count++;
            lastEnd = playerTimeRange[i][1];
        }
    }

    return count;
};
